	OUReportwidgetObject.title = ''; // needs data to set
	OUReportwidgetObject.o = 'title';
	OUReportwidgetObject.d = 'asc';
	OUReportwidgetObject.table = 'sys_report';
	OUReportwidgetObject.filter = 'primary_assignee=';  // needs key added inline
	OUReportwidgetObject.view = 'Default View';
	var relatedTaskOUListwidgetObject = {};
