	function resetDiagram(){
		if(diagram != undefined){
			myOverview.div = null;
			myOverview = null;
		}		
		drawTree();
		resizeDiagram();
		// STRY0116823
		myOverview =  $go(go.Overview, "myOverview",
    { observed: diagram}); // , contentAlignment: go.Spot.Center

	}

	function resizeDiagram() {
		// DFCT0010275
		if($scope.data.map.length > 0){	
				// STRY0096158 - ORG - Template Tree Min Size to avoid cutting off tool tip
				// STRY0116823				
				//				var diagramHeight = parseInt(diagram.documentBounds.height > diagramMinHeight? diagram.documentBounds.height: diagramMinHeight);
				//				var diagramHeight = 500;
				var panelHeight = angular.element(document.getElementById('main_body')).height();
				var headingHeight = angular.element(document.getElementById('panel_heading')).height();
				var titleHeight = angular.element(document.getElementById('panel_title')).height();
				var zoomNoteHeight = angular.element(document.getElementById('span_zoom_note')).height();
				var footerHeight = angular.element(document.getElementById('panel_footer')).height();
				var map_page_Height = minHeight + panelHeight - (headingHeight + titleHeight + footerHeight + zoomNoteHeight);
				//				jQuery("#" + node_id).height(map_page_Height);
				angular.element(document.getElementById(node_id)).height(map_page_Height + 'px');
		}
		// Select the node using the sys_id parameter supplied.
		var node_select = diagram.findNodeForKey(c.data.selectedId);
		diagram.select(node_select);
	}

	function drawTree() {
		if(diagram != undefined){
			diagram.div = null;
			diagram = null;
		}

		// STRY0072032
		if(!c.data.isSystemTreeOrientationVertical){
			// Horizontal Settings
			diagram =
				$go(go.Diagram, node_id, {
				allowZoom: true,
				// define the layout for the diagram
				layout: $go(go.TreeLayout, { nodeSpacing: 5, layerSpacing: 60 })
			});
		} else{
			diagram =
				$go(go.Diagram, node_id, {
				allowZoom: true,
				// define the layout for the diagram
				layout: $go(go.TreeLayout, { angle:90, nodeSpacing: 5, layerSpacing: 60 })
			});
		}

		diagram.model = new go.TreeModel($scope.data.map);
		var fontStyle = "14px Segoe UI";
		//var font = "13px Helvetica, Arial, sans-serif";
		// Define a simple node template consisting of text followed by an expand/collapse button
		// STRY0072032
		var treeOrientation;
		if(!c.data.isSystemTreeOrientationVertical){
			treeOrientation = "Horizontal";
		} else {
			treeOrientation = "Vertical";
		}
		diagram.nodeTemplate = 
			$go(go.Node, treeOrientation,
					{ selectionAdorned: false,
					 selectionChanged: nodeSelectionChanged,
					 isTreeExpanded: true,
					 isTreeLeaf: true
					},  // this event handler is defined below

					// on hover over node, show the icons
					{mouseEnter: function(e, obj) {
						obj.findObject('gradientRectangle').opacity =  c.data.isFullScreen ? icon_opacity_normal : 0.0;
						obj.findObject('Icons').visible=c.data.isFullScreen;
					},
					 mouseLeave: function(e, obj) {
						 obj.findObject('gradientRectangle').opacity = 0.0;
						 obj.findObject('Icons').visible=false;
