													$go(go.Panel, "Horizontal", {alignment: go.Spot.Left,
																											 margin: new go.Margin(18, 0, 0, 0)},  // Horizontal panel for Task Manager and Administrator
															addImage(c.data.taskManagerImage, 1.0, c.data.titleTaskManagers, "tasking_authorities_list"),
															addImage(c.data.Admin16Image, 1.0, c.data.titleOUHierarchyAdministrators, "u_ou_hierarchy_administrators_list")
														 ),	// end horizonal panel for icons
													// DFCT0010761 =- changed the height to 35, marin to margin: new go.Margin(0, 5, 0, 5),
													$go(go.TextBlock, {alignment: go.Spot.Left, textAlign:"left", font: fontStyle, stroke: "white", margin: 5, minSize: new go.Size(250, 35), maxSize: new go.Size(250, 55) },
															new go.Binding("text", "name"))
