							$go(go.Shape, "Circle", 
									{visible: false,
									 // STRY0114088, STRY0113936
									 width: iconCircleSize, strokeWidth: outlineWidth, 
									 // STRY0113936
									 alignment: new go.Spot(1, 1, rightIconCornerOffset, bottomIconCornerOffset)},
									new go.Binding("visible", "", function (data){
										if(data.u_outstanding_request_count && c.data.isFullScreen)
											return data.isAdmin && data.u_outstanding_request_count > 0;
										else
											return false;}),
									new go.Binding("fill", "active", function (t){
										if(t)
											return node_active_bg;
										else
											return node_inactive_bg;}),
									// if selected, outline the circle
									new go.Binding("stroke", "", function(node){
										if (node.isSelected)
											return node_selected_border; 
										else if(node.data.active)
											return node_active_bg;
										else
											return node_inactive_bg;}).ofObject("")
								 ),
							$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
									// STRY0113936
									{alignment: new go.Spot(1, 1, rightIconCornerOffset, bottomIconCornerOffset)}, 
									new go.Binding("visible", "", function (data){
										if(data.u_outstanding_request_count && c.data.isFullScreen)
											return data.isAdmin && data.u_outstanding_request_count > 0;
										else
											return false;}),
									addImage(c.data.ouProcessRequestImage, c.data.topIconOpacity, '', '')
								 ) // end panel holding circle and unlock icon
						 ),
					$go("TreeExpanderButton") // this was overkill for small diagrams (shows the icon to expand/collapse)
				 );
		diagram.select(diagram.findNodeForKey(c.data.selectedId));
		diagram.allowVerticalScroll=true;
		// Define a trivial link template with no arrowhead
		diagram.linkTemplate = $go(go.Link, { selectable: false }, $go(go.Shape));  // the link shape

		if(c.data.selectPercent=="tree"){
			diagram.initialAutoScale = go.Diagram.Uniform;
		} else {
			diagram.scale = parseInt(c.data.selectPercent)/100;
		}

		diagram.commandHandler.scrollToPart(diagram.findNodeForKey(c.data.selectedId));
	}
};

