// 2.7.0 | 2021-10-20 | raj | STRY0112710 - HHS- Strong Matrix- Permissive OU Tasking- Visual Indicators- Tooltips
//                            STRY0111072 - Organizational Hierarchy Full-screen–- OU Management Icons- Add Tooltips  
//                            STRY0111076 - Organizational Hierarchy Full-screen– Adjust Ordering of Icons- Related Tasks Icon  
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-24 | raj  | DFCT0010594 - "Organizational Hierarchy in full-screen view" displays an empty modal
//                                         Changes made in HTML
// 2.7.0 | 2021-10-27 | raj  | STRY0113084 - Templates- Duration Fields- Update Label and Info Text
//                                         Changes made in Client Script and Server Script
// 2.7.0 | 2021-11-01 | raj  | DFCT0010620 - Body & Subject Incorrect: Response for OU Request Email is going to ${Responder} NOT ${Requestor} , URL for Order By was not right.
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-01 | raj  | DFCT0010634 - "Report" icon is displaying in Full Screen view
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-01 | raj  | STRY0114110 - Org Hierarchy Full Screen- Tree Node- Hover-panel "Style Update" for Inactive OUs
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-11 | raj  | STRY0113881 - Org Hierarchy Full Screen- Tree Node- "Process Request" Indicator
//                                         Changes made in Server Script
// 2.7.0 | 2021-12-06 | raj  | STRY0113936 - Org Hierarchy Full Screen- Tree Node- "Process Request" Indicator- Styling & Popover Update
//														 STRY0114088 - Org Hierarchy Full Screen- Tree Node- Highlight Styling
//														 STRY0113884 - Org Hierarchy Full Screen- Tree Node- Permissive Tasking Indicator Styling
//                                         Changes made in Client Controller
// 2.7.101 | 2021-12-26 | raj  | STRY0116017 - Org Hierarchy Fullscreen- Member List Modal- Service Portal view as default
//										Changes in Client controller only - comment added in a nother update set
// 2.7.101 | 2022-01-04 | raj  | DFCT0010275 - New Tasker Setup - Not able to create initial/parent OU
//										Changes in Server, Client controller and HTML
// 2.7.2 | 2022-01-06 | raj  | STRY0115843 - Org Hierarchy Fullscreen- OU Information Modal- Match information displayed on split-view
//										Changes Client controller
// 2.7.0 | 2021-11-01 | raj  | DFCT0010634 - "Report" icon is displaying in Full Screen view
//                                      Changes made in Client Script
// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
//                                      In Client controller, added code for footerstyle display none; added missing semicolons
//                                      Changes made in Client controller
// 2.8 | 2022-01-19 | raj  | STRY0116812 - TECH - Update Org Tree to handle record watcher the same way Task and Template do (no diagram redraw)
//                                      Changes made in Server Script and Client controller
// 2.8 | 2022-01-19 | raj  | STRY0113679 - Org Hierarchy Tree- Update Fullscreen Icon to open in current tab
//                                      Changes made in Server Script and HTML
// 2.8 | 2022-01-25 | raj  | STRY0116822 - Org Hierarchy Tree- Bifold Widget and Fullscreen view- Fit to screen and internally scrollable
//                                      Changes made in Server Client controller and HTML
// 2.8 | 2022-01-25 | raj  | STRY0116823 - Org Hierarchy Tree- Bifold Widget and Fullscreen view- Add Picture-in-picture feature
//                                      Changes made in Server Client controller and HTML and CSS
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
	data.placeholderMsg = gs.getMessage("Select Task...");
	// STRY0108231
	data.page_id = $sp.getParameter("id");

	// TODO - GET THIS SETTING FROM THE OPTIONS INSTEAD OF LOOKING AT A PAGE ID
	// ONCE COMING FROM OPTIOIN, UPDATE THIS SETTING TO NOT USE PAGE ID, UPDATE
	// ALL PAGES WHERE FULL SCREEN DESIRED TO TRUE AND THE REST SHOULD BE FINE
	data.isFullScreen = data.page_id == 'discovertasker_ouhierarchy_full_screeen';
	// STRY0111888
	data.permissiveOn = gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off';
	// STRY0105791
	data.baseURL = gs.getProperty('glide.servlet.uri');
	// DFCT0010565
	if($sp.getPortalRecord()){
		data.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
	} else {
		// TODO: May want to pull default from the form load here
		data.service_portal_url_suffix = '';
	}

	// TODO - GET FROM MESSAGE
	data.informationModal = gs.getMessage('Organizational Unit Information');
	data.subOUModal = gs.getMessage('List of Sub OUs');
	data.memberOUModal = gs.getMessage('List of Members');
	data.contactsOUModal = gs.getMessage('List of Contacts');
	data.reportOUModal = gs.getMessage('OU Reports for ');
	data.relatedTasksOUModal = gs.getMessage('Related Tasks');	
	data.newOURequestChangeModal = gs.getMessage('Tasker - Title - Request Hierarchy Update');
	data.newSubOUModal = gs.getMessage('Create New Sub OU');

	// STRY0113679
	data.OrgFullscreen16 = {"src":'Fullscreen16.svg', "title": gs.getMessage("Open Organizational Hierarchy in full screen in current tab"), "alt": gs.getMessage('Full Screen View')};
	data.MinimizeFullScreen16 = {"src":'MinimizeFullScreen16.svg', "title": gs.getMessage("Open Organizational Hierarchy in bifold screen in current tab"), "alt": gs.getMessage('Bifold View')};

	// TODO - ADD TO WIDGET OPTIONS - LEFT OFF FOR NOW
	data.include_poc_avatar = true;

	data.table = 'x_153465_discovert_discover_office_hierarchy';
	data.titleTaskManagers = gs.getMessage('Tasker - Title - TASK MANAGERS');
	data.titleOUHierarchyAdministrators = gs.getMessage('Tasker - Title - OU HIERARCHY ADMINISTRATORS');
	var map = data.map = [];

	data.topParentNeeded = false;
	// STRY0074597 default to true, will change later if input
	data.topOnly = true;
	var count = new GlideAggregate('x_153465_discovert_discover_office_hierarchy');
	// DFCT0010275 - use addNullQuery for a null query instead of a string value
	count.addNullQuery('parent');
	count.addAggregate('COUNT');
	count.query();
	var topHierarchy = 0;
	if(count.next())
		topHierarchy = count.getAggregate('COUNT');

	if (topHierarchy < 1 ) {
		data.topParentNeeded = true;
		return;
	}
	// STRY0072032
	data.isSystemTreeOrientationVertical = new tasking_System_Settings_Scripts().systemControlSetting().VerticalTree;

	// STRY0116812
	var defaultIdTopOfficeHierarchy = null;
	var prefPercent = 'DTechApps.Tasker.selectPercent';
	var prefFavorite = 'DTechApps.Tasker.FavoriteOU';
	data.currentUser = gs.getUserID();
	var orgScripts = new OrganizationalScripts();
	// set the default selected id
	data.selectedId = $sp.getParameter("sys_id");
	// getDefaultId for user
	var defaultOUId = orgScripts.GetUserDefaultOU(data.currentUser) + '';
	// get top ou for the user based on default id
	var defaultOUTopId =orgScripts.getTopOUId(defaultOUId);
	data.defaultOU = {value: defaultOUId,
										topId: defaultOUTopId};

	// RJ -ET - Story 4
	// if the user selected a TOP OU, then rebuild the tree with the selected topOU
	if(input){
		// save percent change and return
		if(input.percentChanged){
			data.selectPercent = input.selectPercent;
			gs.getUser().savePreference(prefPercent, input.selectPercent);
			return;
		}
		if(input.favorityChanged){
			data.favorite = input.favorite;
			gs.getUser().savePreference(prefFavorite, JSON.stringify(input.favorite));
			return;
		}
		if(input.topOU){
			// only set if passed in to the input
			defaultIdTopOfficeHierarchy = input.topOU;
			// if the user changed the top OU, then set the id to the new top
			data.selectedId = input.topOU;
		}
		// STRY0074597 
		data.topOnly = input.topOnly;
		if(!input.buildIcons)
			buildIcons();
	} else {
		buildIcons();
		var selectPercent = gs.getUser().getPreference(prefPercent);
		if(selectPercent){
			data.selectPercent = selectPercent;
		} else {
			data.selectPercent = 100;
		}
		var favoriteOU = gs.getUser().getPreference(prefFavorite);
		if(favoriteOU){
			data.favorite = JSON.parse(favoriteOU);
			// do not override the URL on load
			if(!data.selectedId && data.selectedId != ''){
				data.selectedId = data.favorite.value;
			}
		} else {
			data.favorite = {value: "",	topId: ""};
		}

	}

	// do not override the URL or the favorite on load
	if(!data.selectedId && data.selectedId != ''){
		data.selectedId = data.defaultOU.value;
	}

	// STRY0116812 - changed to not grab any top ou
	// if the top ou was set, then the user passed a new top in input above
	// if not, then we get the top id for the current selected id
	if (defaultIdTopOfficeHierarchy == null) {
		// set top based on selected id b/c it was on the URL
		defaultIdTopOfficeHierarchy = orgScripts.getTopOUId(data.selectedId);
	}

	// RJ -ET - Story 4
	var gr_ou = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');

	if (!gr_ou.get(defaultIdTopOfficeHierarchy)) {
		// if the glide record isn't found, rather than returning no tree
		// find the first top OU and load the tree for it
		gr_ou.addNullQuery('parent');
		gr_ou.query();
		gr_ou.next();	
	}

	//--------------------------------------------------------------------------------------
	// if the default OU is in the tree, then set the default ID to the user's default
	// if the default OU is not in the tree, then, default to top ou
	// OR a favorite ... to be implemented later
	if(defaultIdTopOfficeHierarchy == data.defaultOU.topId){
		data.id = data.defaultOU.value;
	} else {
		data.id = gr_ou.getValue('sys_id');
	}
// TODO - CLEAN UP THIS IS A MESS, WHY DO WE HAVE SO MANY VARIABLES
// THIS IS OLD PREVIOUS DEVELOPER MESS
	var id = data.id;
	data.title = gr_ou.getValue('office_abbreviation');

	if (!id) {
		data.id = null;
		return;
	}

	// STRY0108231
	data.sys_id=data.id;
	// STRY0101474  - DFCT0010275
	data.isGHA = new	UserInfoScripts().UserHasRole('x_153465_discovert.tasker_organizational_admin');

	// STRY0116812
	data.currentTopOU = defaultIdTopOfficeHierarchy;


	var taskWidgetData = new TaskWidgetData();
	data.fieldsInModel = taskWidgetData.loadOfficeTreeFieldsAndFieldLabels(gr_ou);

	taskWidgetData.buildOUMap('discovertasker-officehierarchy', map, gr_ou, data.fieldsInModel);

	function buildIcons(){
		// STRY0108231
		// RAJ - NOTE performance, load these 1 time, added if logic.  also moved into fucntion to clean up code
		// --- Get Task Manager Image
		// STRY0111072 - STRY0111072
		data.taskManagerImage = buildIcon({imageName: 'Tie16.svg',
																			title: '',
																			alt:''
																		 });		
		// --- Get Admin Image
		// STRY0111072 - STRY0111072
		data.Admin16Image = buildIcon({imageName: 'Admin16.svg',
																			title: '',
																			alt:''
																		 });
		// STRY0101474 
		// --- Get Related Tasks Image
		// STRY0111072 - STRY0111072
		data.ouRequestChangeImage = buildIcon({imageName: 'Request16.svg',
																			title: 'Open Request Organizational Update',
																			alt:'Open Request'
																		 });		
		// --- Get OU Process Request Image
		// STRY0111072 - STRY0111072
		data.ouProcessRequestImage = buildIcon({imageName: 'ProcessRequestBadge24.svg',
																			title: 'Click to respond to the Organizational Request',
																			alt:'Open Request List'
																		 });
		// --- Get OU Information Image
		// STRY0111072 - STRY0111072
		data.ouInformationImage = buildIcon({imageName: 'Information16.svg',
																			title: 'Open Organizational Unit Information',
																			alt:'Open Information'
																		 });
		// STRY0111072 - STRY0111072
		data.ouSubOUImage = buildIcon({imageName: 'SubOU16.svg',
																			title: 'Open List of Sub Organization Units',
																			alt:'Open Sub Organization Unit List'
																		 });
		// --- Get OU Members Image
		// STRY0111072 - STRY0111072
		data.ouMembersImage = buildIcon({imageName: 'OUMembers16.svg',
																			title: 'Open List of Members',
																			alt:'Open Member List'
																		 });
		// --- Get OU Contacts Image
		// STRY0111072 - STRY0111072
		data.ouContactsImage = buildIcon({imageName: 'Contacts16.svg',
																			title: 'Open List of Contacts',
																			alt:'Open Contact List'
																		 });
		// --- Get OU Reports Image
		// STRY0111072 - STRY0111072
		data.ouReportImage = buildIcon({imageName: 'Reports16.svg',
																			title: 'Go to Reports',
																			alt:'Go to Reports'
																		 });		
		// STRY0101474
		// --- Get Related Tasks Image
		// STRY0111072 - STRY0111072
		data.ouRelatedTasksImage = buildIcon({imageName: 'RelatedTasks16.svg',
																			title: 'Open Related Tasks',
																			alt:'Open Task List'
																		 });
		// --- Get Divider Image
		// STRY0111072 - STRY0111072
		data.dividerImage = buildIcon({imageName: 'Divider.svg',
																			title: '',
																			alt:''
																		 });
		// --- Get Create Sub OU Image
		// STRY0111072 - STRY0111072
		data.createSubOUImage = buildIcon({imageName: 'GenericAddSub16.svg',
																			title: 'Create Sub OU',
																			alt:'Add Sub OU'
																		 });	

		// STRY0111888 - STRY0111072 - STRY0111072
		data.LockOpenBadge24 = buildIcon({imageName: 'LockOpenBadge24.svg',
																			title: 'Permissive Organizational Unit',
																			alt:'OU is Permissive'
																		 });

		// STRY0113668
		data.Divider = buildIcon({imageName: 'Divider_Black.svg',
																			title: '',
																			alt:''
																		 });

		data.ZoomEntire24 = buildIcon({imageName: 'ZoomEntire24.svg',
																			title: 'View the Entire Organization',
																			alt:'Entire Organization'
																		 });
		data.ZoomSelected24 = buildIcon({imageName: 'ZoomSelected24.svg',
																			title: 'Zoom into Selected OU',
																			alt:'Selected OU'
																		 });
		data.Favorite24 = buildIcon({imageName: 'Favorite24.svg',
																			title: 'Navigate to Favorited OU',
																			alt:'Favorite OU'
																		 });
		data.DefaultOU24 = buildIcon({imageName: 'DefaultOU24.svg',
																			title: 'Navigate to my default OU',
																			alt:'Default OU'
																		 });
		data.TopOU24 = buildIcon({imageName: 'TopOU24.svg',
																			title: 'Navigate to Top OU',
																			alt:'Top OU'
																		 });
		data.AddToFavorite24 = buildIcon({imageName: 'AddToFavorite24.svg',
																			title: 'Set selected as Favorite OU',
																			alt:'Add Favorite'
																		 });
		data.FavoriteFilled24 = buildIcon({imageName: 'FavoriteFilled24.svg',
																			title: 'This is your selected Favorite OU',
																			alt:'Selected Favorite'
																		 });

		// DFCT0010275
		data.buildIcons = true;
	}

	// STRY0101474
	//------------------------------------------------------------------------------------------------------------------------
	// buildIcon({imageName: [image name in db_image table],
	//												title: [message key or text for the tooltip for icon],
	//												alt:' [message key or text for the alt value]
	//           })
	function buildIcon(params){
		var grImage = new GlideRecord("db_image");
		var image;
		grImage.addQuery('name',params.imageName);
		grImage.query();
		if(grImage.next()){
			image=grImage.getDisplayValue();
		}
		var icon = {
			src:image, 
			title: gs.getMessage(params.title), 
			alt:gs.getMessage(params.alt)
		};		
		return icon;
	}
})($sp, input, data, options, gs);
